  background: #fff;
  box-shadow: 0 10px 28px rgba(3, 10, 18, 0.12);
}
.dashWidget__menu.is-open .dashWidget__menuPanel{
  display: block;
}
.dashWidget__menuItem{
  display: flex;
  align-items: center;
  gap: 6px;
