  color: var(--text);
  opacity: 0.85;
}
.dashWidget__fitCols:hover{
  border-color: rgba(16, 80, 96, 0.45);
  color: var(--text);
  opacity: 1;
  background: linear-gradient(135deg, rgba(16, 80, 96, 0.12), rgba(160, 128, 80, 0.08));
}
