options.onRender:
const el = (id) => htmlNode.getElementById(id);
const themeRootEl = htmlNode.querySelector(".master") || htmlNode;
const themeButtons = [...htmlNode.querySelectorAll("[data-theme-set]")];
const normalize = (s) => String(s ?? "").replace(/[−–—]/g, "-").trim();

const escapeHtml = (value) =>
  String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
