const resolveDashboardVar = (name) => {
  const key = normalize(name);
  if (!key) return "";
  try {
    const qp = new URLSearchParams(window.location.search || "");
    const fromUrl = normalize(qp.get(`var-${key}`));
    if (fromUrl) return fromUrl;
  } catch {
    /* ignore */
  }
  const tryReplace = (fn) => {
    if (typeof fn !== "function") return "";
    for (const expr of [`\${${key}}`, `$${key}`, `\${${key}:text}`, `\${${key}:json}`]) {
      try {
        const v = normalize(fn(expr));
        if (!v || v === expr || v === `$${key}` || v === `\${${key}}`) continue;
        if (v === `\${${key}:text}` || v === `\${${key}:json}`) continue;
        return v;
      } catch {
        /* ignore */
      }
    }
    return "";
  };
  if (typeof htmlGraphics !== "undefined") {
    const fromProps = tryReplace((expr) => htmlGraphics?.props?.replaceVariables?.(expr));
    if (fromProps) return fromProps;
    const srv = htmlGraphics?.getTemplateSrv?.();
    const fromSrv = tryReplace((expr) => srv?.replace?.(expr));
    if (fromSrv) return fromSrv;
  }
  if (typeof replaceVariables === "function") {
    const fromGlobal = tryReplace((expr) => replaceVariables(expr));
    if (fromGlobal) return fromGlobal;
  }
  return "";
};

