const UNIT_MS = { s: 1000, m: 60 * 1000, h: 3600 * 1000, d: 86400 * 1000, w: 7 * 86400 * 1000, M: 30 * 86400 * 1000 };

/** Поддержка `now`, `now-6h`, `now+30m`, ISO и строк, понимаемых Date.parse. */
const parseTimeExpression = (raw, anchorMs) => {
  const s0 = normalize(raw).replace(/\s+/g, " ");
  if (!s0) return NaN;
  const sl = s0.toLowerCase();
  if (sl === "now") return anchorMs;
  const m = /^now([+-])(\d+(?:\.\d+)?)([smhdw]|mo)$/i.exec(sl);
  if (m) {
    const sign = m[1] === "-" ? -1 : 1;
    const n = Number(m[2]);
    let u = m[3].toLowerCase();
    if (u === "mo") u = "M";
    const mul = UNIT_MS[u];
    if (!Number.isFinite(n) || !mul) return NaN;
    return anchorMs + sign * n * mul;
  }
  const parsed = Date.parse(s0);
  return Number.isFinite(parsed) ? parsed : NaN;
};

const isRelativeTimeInput = (raw) => /\bnow\b/i.test(normalize(raw));

const relativeNowOffsetMs = (raw) => {
  const s = normalize(raw).replace(/\s+/g, " ").toLowerCase();
  const m = /^now([+-])(\d+(?:\.\d+)?)([smhdw]|mo)$/i.exec(s);
  if (!m) return null;
  const sign = m[1] === "-" ? -1 : 1;
  const n = Number(m[2]);
  let u = m[3].toLowerCase();
  if (u === "mo") u = "M";
  const mul = UNIT_MS[u];
  if (!Number.isFinite(n) || !mul) return null;
  return sign * n * mul;
};

const msToDatetimeLocalValue = (ms) => {
