};

const parseDateInputToMs = (s, boundary) => {
  const v = normalize(s);
  if (!v) return NaN;
  const m = /^(\d{4})-(\d{2})-(\d{2})$/.exec(v);
  if (m) {
    const y = Number(m[1]);
    const mo = Number(m[2]) - 1;
    const d = Number(m[3]);
    if (!Number.isFinite(y) || mo < 0 || mo > 11 || d < 1 || d > 31) return NaN;
    const t =
      boundary === "end"
        ? new Date(y, mo, d, 23, 59, 59, 999).getTime()
        : new Date(y, mo, d, 0, 0, 0, 0).getTime();
    return Number.isFinite(t) ? t : NaN;
  }
  return NaN;
};

