/** Время точки → микросекунды (число); `format:true` даёт ISO-строки. */
const pointTimeToUs = (raw) => {
  if (typeof raw === "number" && Number.isFinite(raw)) {
    return raw < 1e14 ? Math.round(raw * 1000) : Math.round(raw);
  }
  if (typeof raw === "string") {
    const ms = Date.parse(raw);
    return Number.isFinite(ms) ? Math.round(ms * 1000) : NaN;
  }
  return NaN;
};

const looksLikePointTime = (raw) => {
  if (typeof raw === "number" && Number.isFinite(raw)) return Math.abs(raw) > 1e9;
  if (typeof raw === "string") return Number.isFinite(Date.parse(raw));
  return false;
};

const pointValueToNumber = (raw) => {
  if (typeof raw === "number") return raw;
  if (raw && typeof raw === "object" && "value" in raw) return Number(raw.value);
  return Number(raw);
};

const isRealPoint = (p) => !Array.isArray(p) || p[2] !== false;

/** tagId -> массив [tМкс, yЧисло, архивнаяТочка] */
const pointsFromBlock = (block, { real = true } = {}) => {
  const pts = Array.isArray(block?.data) ? block.data : [];
  const out = [];
  for (const p of pts) {
    if (!Array.isArray(p) || p.length < 2) continue;
    const timeFirst = looksLikePointTime(p[0]);
    const valueFirst = looksLikePointTime(p[1]);
    const t = pointTimeToUs(timeFirst || !valueFirst ? p[0] : p[1]);
    const y = pointValueToNumber(timeFirst || !valueFirst ? p[1] : p[0]);
    if (!Number.isFinite(t)) continue;
    if (!Number.isFinite(y)) continue;
    out.push([t, y, real]);
  }
  out.sort((a, b) => a[0] - b[0]);
  return out;
};

const mergePoints = (a, b) => {
  const m = new Map();
  const add = (row) => {
    if (!Array.isArray(row) || row.length < 2 || !Number.isFinite(row[0]) || !Number.isFinite(row[1])) return;
    const next = [row[0], row[1], isRealPoint(row)];
    const prev = m.get(row[0]);
    if (prev && isRealPoint(prev) && !next[2]) return;
    m.set(row[0], next);
  };
  for (const row of a || []) add(row);
  for (const row of b || []) add(row);
  return [...m.values()].sort((x, y) => x[0] - y[0]);
};

const pointsInRange = (points, startUs, endUs) =>
  (points || []).filter(
    (p) =>
      Array.isArray(p) &&
      p.length >= 2 &&
      Number.isFinite(p[0]) &&
      Number.isFinite(p[1]) &&
      p[0] >= startUs &&
      p[0] <= endUs
  );

const hasRealPointInRange = (points, startUs, endUs) => pointsInRange(points, startUs, endUs).some(isRealPoint);

const trimWindow = (points, minTUs) => {
  if (!Array.isArray(points)) return [];
  return points.filter((p) => Array.isArray(p) && p[0] >= minTUs);
};

const trimWindowKeepingCarry = (points, minTUs) => {
  if (!Array.isArray(points) || !Number.isFinite(minTUs)) return [];
  const sorted = points
    .filter((p) => Array.isArray(p) && p.length >= 2 && Number.isFinite(p[0]) && Number.isFinite(p[1]))
    .sort((a, b) => a[0] - b[0]);
  let carry = null;
  const kept = [];
  for (const p of sorted) {
    if (p[0] <= minTUs) carry = p;
    else kept.push([p[0], p[1], isRealPoint(p)]);
  }
  if (carry) kept.unshift([minTUs, carry[1], false]);
  return mergePoints([], kept);
};

