const GRID_COLS = 24;
const GRID_MIN_W = 4;
const WIDGET_TYPE_CHART = "tag-chart";
const WIDGET_TYPE_VALUE = "tag-value";

const widgetTypeOf = (item) => (item?.type === WIDGET_TYPE_VALUE ? WIDGET_TYPE_VALUE : WIDGET_TYPE_CHART);
const isChartWidget = (item) => widgetTypeOf(item) === WIDGET_TYPE_CHART;
const isValueWidget = (item) => widgetTypeOf(item) === WIDGET_TYPE_VALUE;
const widgetTitleOf = (item) => (isValueWidget(item) ? "Текущее значение" : "График");

const rectsOverlap = (a, b) => {
  if (a.x + a.w <= b.x || b.x + b.w <= a.x) return false;
  if (a.y + a.h <= b.y || b.y + b.h <= a.y) return false;
  return true;
};

const packGridLayout = (layout) => {
  const n = layout.length;
  const order = [...Array(n).keys()].sort((i, j) => {
    const a = layout[i];
    const b = layout[j];
    if (a.y !== b.y) return a.y - b.y;
    if (a.x !== b.x) return a.x - b.x;
    return i - j;
  });
  const placed = [];
  for (const i of order) {
    let w = { ...layout[i] };
    let guard = 0;
    while (guard++ < 400) {
      let bump = 0;
      for (const p of placed) {
        if (rectsOverlap(w, p)) bump = Math.max(bump, p.y + p.h - w.y);
      }
      if (bump <= 0) break;
      w.y += bump;
    }
    placed.push(w);
    Object.assign(layout[i], w);
  }
};

const clampItem = (item) => {
  const type = widgetTypeOf(item);
  const defaultW = type === WIDGET_TYPE_VALUE ? 8 : 12;
  const defaultH = type === WIDGET_TYPE_VALUE ? 2 : 3;
  const w = Math.min(GRID_COLS, Math.max(GRID_MIN_W, Number(item.w) || defaultW));
  const h = Math.max(2, Math.min(24, Number(item.h) || defaultH));
  let x = Math.max(0, Math.min(GRID_COLS - w, Number(item.x) || 0));
  let y = Math.max(0, Number(item.y) || 0);
  const out = {
    id: String(item.id),
    type,
    x,
    y,
    w,
    h,
    tagIds: Array.isArray(item.tagIds) ? item.tagIds.map(normalize).filter(Boolean) : [],
    tagPickerCollapsed: item.tagPickerCollapsed === true
  };
  if (type === WIDGET_TYPE_CHART) out.relativeYAxes = item.relativeYAxes === true;
  return out;
};

const findFreeSlot = (layout, w, h) => {
  const ww = Math.min(GRID_COLS, w);
  for (let y = 0; y < 80; y++) {
    for (let x = 0; x <= GRID_COLS - ww; x++) {
      const probe = { x, y, w: ww, h };
      if (!layout.some((it) => rectsOverlap(probe, it))) return { x, y };
    }
  }
  const maxY = layout.reduce((m, it) => Math.max(m, it.y + it.h), 0);
  return { x: 0, y: maxY };
};

let layoutState = [];

const loadLayout = () => {
  try {
    const raw = localStorage.getItem(LAYOUT_KEY);
    const arr = JSON.parse(raw || "null");
    if (!Array.isArray(arr) || !arr.length) {
      const { x, y } = findFreeSlot([], 12, 3);
      return [clampItem({ id: newWidgetId(), type: WIDGET_TYPE_CHART, x, y, w: 12, h: 3, tagIds: [] })];
    }
    const out = [];
    for (const row of arr) {
      if (!row || typeof row !== "object") continue;
      const id = normalize(row.id);
      if (!id) continue;
      out.push(clampItem({ ...row, id }));
    }
    return out.length ? out : loadLayout();
  } catch {
    const { x, y } = findFreeSlot([], 12, 3);
    return [clampItem({ id: newWidgetId(), type: WIDGET_TYPE_CHART, x, y, w: 12, h: 3, tagIds: [] })];
  }
};


