  try {
    const p = String(window.location?.pathname || "");
    const idx = p.indexOf("/d/");
    if (idx > 0) return p.slice(0, idx).replace(/\/+$/, "");
  } catch {
    /* ignore */
  }
  return "";
};

/** Относительный URL API Grafana в браузере (без внутреннего hostname из appUrl). */
const grafanaApiUrl = (path) => {
  const suffix = String(path || "").startsWith("/") ? String(path) : `/${path}`;
  const sub = grafanaSubPath();
  return sub ? `${sub}${suffix}` : suffix;
};

