const saveBoardConfigForAll = async () => {
  const btn = el("saveForAllBtn");
  if (btn) btn.disabled = true;
  showSaveForAllStatus("Сохранение…");
  try {
    const uid = dashboardStorageSlug();
    if (!uid || uid === "nodashboard") throw new Error("UID дашборда не найден");

    const getRes = await fetch(grafanaApiUrl(`/api/dashboards/uid/${encodeURIComponent(uid)}`), {
      credentials: "same-origin",
      headers: { Accept: "application/json" }
    });
    if (!getRes.ok) throw new Error(`Не удалось прочитать дашборд (${getRes.status})`);
    const payload = await getRes.json();
    const dash = payload?.dashboard;
    if (!dash) throw new Error("Пустой ответ дашборда");
    if (!canSaveDashboardForAll() && !metaAllowsDashboardSave(payload?.meta)) {
      throw new Error("Недостаточно прав для сохранения дашборда");
    }

    const panelId = Number(htmlGraphics?.props?.id ?? 1);
    const panels = Array.isArray(dash.panels) ? dash.panels : [];
    const panel = panels.find((p) => Number(p?.id) === panelId) || panels[0];
    if (!panel?.options) throw new Error("Панель HTML Graphics не найдена");

    const props = readPanelCustomProps();
    props.tagChartsShared = buildSharedBoardConfig();
    const codeDataStr = JSON.stringify(props, null, 2);
    panel.options.codeData = codeDataStr;

    const saveRes = await fetch(grafanaApiUrl("/api/dashboards/db"), {
      method: "POST",
      credentials: "same-origin",
      headers: { "Content-Type": "application/json", Accept: "application/json" },
      body: JSON.stringify({
        dashboard: dash,
        message: "Сохранена общая конфигурация доски «Теги»",
        overwrite: true
      })
    });
    if (!saveRes.ok) {
      let errText = "";
      try {
        const errBody = await saveRes.json();
        errText = normalize(errBody?.message || errBody?.error);
      } catch {
        /* ignore */
      }
      throw new Error(errText || `Ошибка сохранения (${saveRes.status})`);
    }

    writeSharedSeenAt(props.tagChartsShared.savedAt);
    showSaveForAllStatus("Конфигурация сохранена для всех пользователей", "ok");
  } catch (e) {
    showSaveForAllStatus(normalize(e?.message) || "Ошибка сохранения", "error");
  } finally {
    if (btn) btn.disabled = false;
  }
};

const wireSaveForAll = async () => {
