const isoFromUs = (us) => new Date(Math.floor(usToMs(Number(us)))).toISOString();

/** GET `/v1/data/` как в Configurator: параметры запроса передаются отдельными query params, без устаревшего `q`. */
const peresvetReadDataGet = async (tagIds, startUs, finishUs, maxCount = 8000, { actual = true } = {}) => {
  const ids = [...new Set((tagIds || []).map(normalize).filter(Boolean))];
  if (!ids.length) return null;
  const params = new URLSearchParams();
  ids.forEach((id) => params.append("tagId", id));
  params.append("start", isoFromUs(startUs));
  params.append("finish", isoFromUs(finishUs));
  params.append("format", "true");
  if (actual) params.append("actual", "true");
  params.append("maxCount", String(maxCount));
  const url = `${apiRoot()}/data/?${params.toString()}`;
  return peresvetGetJson(url, { cache: "no-store" });
};

const peresvetReadDataAtGet = async (tagIds, finishUs) => {
  const ids = [...new Set((tagIds || []).map(normalize).filter(Boolean))];
  if (!ids.length) return null;
  const params = new URLSearchParams();
  ids.forEach((id) => params.append("tagId", id));
  params.append("finish", isoFromUs(finishUs));
  params.append("format", "true");
  params.append("count", "1");
  params.append("maxCount", "1");
  const url = `${apiRoot()}/data/?${params.toString()}`;
  return peresvetGetJson(url, { cache: "no-store" });
};

