const formatAxisNumber = (value) => {
  const n = Number(value);
  if (!Number.isFinite(n)) return "";
  const abs = Math.abs(n);
  if (abs >= 1000) return n.toLocaleString("ru-RU", { maximumFractionDigits: 0 });
  if (abs >= 100) return n.toLocaleString("ru-RU", { maximumFractionDigits: 1 });
  if (abs >= 1) return n.toLocaleString("ru-RU", { maximumFractionDigits: 2 });
  if (abs === 0) return "0";
  return n.toLocaleString("ru-RU", { maximumFractionDigits: 4 });
};

const formatAxisTimeLabel = (us) => {
  const d = new Date(usToMs(us));
  if (!Number.isFinite(d.getTime())) return "";
  return d.toLocaleTimeString("ru-RU", { hour: "2-digit", minute: "2-digit", second: "2-digit" });
};

const extendPointsToDomain = (points, startUs, endUs) => {
  const sorted = (points || [])
    .filter((p) => Array.isArray(p) && p.length >= 2 && Number.isFinite(p[0]) && Number.isFinite(p[1]))
    .sort((a, b) => a[0] - b[0]);
  if (!sorted.length || !Number.isFinite(startUs) || !Number.isFinite(endUs) || endUs <= startUs) return [];

  let lastBeforeStart = null;
  for (const p of sorted) {
    if (p[0] <= startUs) lastBeforeStart = p;
    else break;
  }

  const inside = sorted.filter((p) => p[0] >= startUs && p[0] <= endUs);
  const out = inside.map((p) => [p[0], p[1], isRealPoint(p)]);

  if (lastBeforeStart) {
    if (!out.length || out[0][0] > startUs) out.unshift([startUs, lastBeforeStart[1], false]);
  } else if (out.length === 1 && out[0][0] > startUs) {
    out.unshift([startUs, out[0][1], false]);
  }

  if (!out.length) return [];
  const last = out[out.length - 1];
  if (last[0] < endUs) out.push([endUs, last[1], false]);
  return mergePoints([], out);
};

const stepPathFromPoints = (points, sx, sy) => {
  if (!points.length) return "";
  const [firstT, firstY] = points[0];
  const parts = [`M${sx(firstT).toFixed(1)},${sy(firstY).toFixed(1)}`];
  for (let i = 1; i < points.length; i++) {
    const [t, y] = points[i];
    const [, prevY] = points[i - 1];
    parts.push(`L${sx(t).toFixed(1)},${sy(prevY).toFixed(1)}`, `L${sx(t).toFixed(1)},${sy(y).toFixed(1)}`);
  }
  return parts.join(" ");
};

const linePathFromPoints = (points, sx, sy) =>
  (points || [])
    .map(([t, y], i) => `${i === 0 ? "M" : "L"}${sx(t).toFixed(1)},${sy(y).toFixed(1)}`)
    .join(" ");

const defaultChartRange = () => {
  const endUs = nowUs();
  return { startUs: endUs - msToUs(5 * 60 * 1000), endUs };
};

const chartRangeFromControls = () => {
  const r = computeQueryRange();
  if (r) return { startUs: r.startUs, endUs: r.endUs };
  if (getCurrentChartRange()) return getCurrentChartRange();
  return defaultChartRange();
};

const chartMaxCountForWidget = (widgetEl) => {
  const stage = widgetEl?.querySelector?.("[data-chart-stage]");
  const width = Math.floor(stage?.getBoundingClientRect?.().width || stage?.clientWidth || 0);
  return Math.max(1, width || 800);
};

const chartMaxCountForSpan = (widgetEl, spanUs, fullSpanUs) => {
  const width = chartMaxCountForWidget(widgetEl);
  if (!Number.isFinite(spanUs) || !Number.isFinite(fullSpanUs) || spanUs <= 0 || fullSpanUs <= 0) return width;
  return Math.max(1, Math.min(width, Math.ceil((width * spanUs) / fullSpanUs)));
};

const findSeriesValueAtTime = (series, targetUs) => {
  const pts = (series?.pts || [])
    .filter((p) => Array.isArray(p) && p.length >= 2 && Number.isFinite(p[0]) && Number.isFinite(p[1]))
    .sort((a, b) => a[0] - b[0]);
  if (!pts.length || !Number.isFinite(targetUs) || targetUs < pts[0][0] || targetUs > pts[pts.length - 1][0]) return null;

  for (let i = 0; i < pts.length; i++) {
    const [t, y] = pts[i];
    if (t === targetUs) return { timeUs: targetUs, value: y };
    if (t > targetUs) {
      const prev = pts[Math.max(0, i - 1)];
      if (!prev) return null;
      if (series.step) return { timeUs: targetUs, value: prev[1] };
      const span = t - prev[0];
      const k = span > 0 ? (targetUs - prev[0]) / span : 0;
      return { timeUs: targetUs, value: prev[1] + (y - prev[1]) * k };
    }
  }

  return { timeUs: targetUs, value: pts[pts.length - 1][1] };
};

const findNearestSeriesValue = (series, targetUs, pointerY, geom) => {
  let best = null;
  for (const s of series) {
    const valueAtTime = findSeriesValueAtTime(s, targetUs);
    if (!valueAtTime) continue;
    const plotH = Math.max(1, geom.H - geom.padT - geom.padB);
    const yPx =
      typeof s.sy === "function"
        ? s.sy(valueAtTime.value)
        : geom.padT + (1 - (valueAtTime.value - geom.minY) / (geom.maxY - geom.minY)) * plotH;
    const distancePx = Math.abs(yPx - pointerY);
    if (distancePx > 18) continue;
    if (!best || distancePx < best.distancePx) best = { series: s, point: [valueAtTime.timeUs, valueAtTime.value], distancePx };
  }
  return best;
};

const findSeriesHitAtCursor = (series, targetUs, pointerY, geom) => {
  const nearY = findNearestSeriesValue(series, targetUs, pointerY, geom);
  if (nearY) return nearY;
  for (const s of series) {
    const valueAtTime = findSeriesValueAtTime(s, targetUs);
    if (valueAtTime) return { series: s, point: [valueAtTime.timeUs, valueAtTime.value], distancePx: 0 };
  }
  return null;
};

const replaceChartStageSvg = (stage, nextStageHtml) => {
