const formatChartTooltipHtml = (tag, tagId, value) => {
  const cn = normalize(tag?.cn || tagId);
  const units = normalize(tag?.prsMeasureUnits || "");
  const description = normalize(tag?.description || "");
  const valueText = units ? `${formatAxisNumber(value)} ${units}` : formatAxisNumber(value);
  const parts = [
    `<div class="tagChartTooltip__name">${escapeHtml(cn)}</div>`,
    `<div class="tagChartTooltip__value">${escapeHtml(valueText)}</div>`
  ];
  if (description) {
    parts.push(`<div class="tagChartTooltip__desc">${escapeHtml(description)}</div>`);
  }
  return parts.join("");
};

const ensureChartTooltip = (panel) => {
  if (!panel) return null;
  let tip = panel.querySelector(":scope > .tagChartTooltip");
  if (!tip) {
    tip = document.createElement("div");
    tip.className = "tagChartTooltip";
    tip.hidden = true;
    panel.appendChild(tip);
  }
  return tip;
};

const wireChartTooltip = (panel, stage, series, geom) => {
  if (!panel || !stage) return;
  ensureChartTooltip(panel);
  stage.__tagChartTooltipSeries = series;
  stage.__tagChartTooltipGeom = geom;

  stage.onmouseleave = () => {
    const t = panel.querySelector(":scope > .tagChartTooltip");
    if (t) t.hidden = true;
  };
  stage.onmousemove = (ev) => {
    const curSeries = stage.__tagChartTooltipSeries || [];
    const g = stage.__tagChartTooltipGeom;
    if (!g || !curSeries.length) return;
    const t = ensureChartTooltip(panel);
    if (!t) return;

    const stageRect = stage.getBoundingClientRect();
    const panelRect = panel.getBoundingClientRect();
    const x = ev.clientX - stageRect.left;
    const y = ev.clientY - stageRect.top;
    const plotW = Math.max(1, g.W - g.padL - g.padR);
    const rel = Math.max(0, Math.min(1, (x - g.padL) / plotW));
    const targetUs = g.minT + rel * (g.maxT - g.minT);
    const hit = findSeriesHitAtCursor(curSeries, targetUs, y, g);
    if (!hit) {
      t.hidden = true;
      return;
    }

    const [, val] = hit.point;
    t.innerHTML = formatChartTooltipHtml(tagInfoById().get(hit.series.id), hit.series.id, val);
    t.hidden = false;
    t.style.left = "0px";
    t.style.top = "0px";
    const tipW = Math.min(t.offsetWidth || 0, panelRect.width - 16);
    const tipH = Math.min(t.offsetHeight || 0, panelRect.height - 16);
    const offsetX = stageRect.left - panelRect.left;
    const offsetY = stageRect.top - panelRect.top;
    let tx = offsetX + x + 12;
    let ty = offsetY + y + 12;
    if (tx + tipW > panelRect.width - 8) tx = offsetX + x - tipW - 12;
    if (ty + tipH > panelRect.height - 8) ty = offsetY + y - tipH - 12;
    tx = Math.max(8, Math.min(panelRect.width - tipW - 8, tx));
    ty = Math.max(8, Math.min(panelRect.height - tipH - 8, ty));
    t.style.left = `${tx}px`;
    t.style.top = `${ty}px`;
  };
};

const seriesYBounds = (pts) => {
  let minY = Infinity;
  let maxY = -Infinity;
  for (const p of pts || []) {
    if (!Array.isArray(p) || p.length < 2 || !Number.isFinite(p[1])) continue;
    minY = Math.min(minY, p[1]);
    maxY = Math.max(maxY, p[1]);
  }
  if (!Number.isFinite(minY) || !Number.isFinite(maxY)) {
    minY = 0;
    maxY = 1;
  } else if (minY === maxY) {
    const pad = Math.abs(minY || 1) * 0.05 + 1e-6;
    minY -= pad;
    maxY += pad;
  } else {
    const pad = (maxY - minY) * 0.08;
    minY -= pad;
    maxY += pad;
  }
  return { minY, maxY };
};

const drawChart = (widgetEl, tagLabels) => {
  const wid = widgetEl.dataset.widgetId;
  const stage = widgetEl.querySelector("[data-chart-stage]");
  const legendEl = widgetEl.querySelector("[data-chart-legend]");
  const emptyEl = widgetEl.querySelector("[data-chart-empty]");
  if (!stage) return;

  const item = layoutState.find((x) => x.id === wid) || {};
  const relativeY = item.relativeYAxes === true;
  widgetEl.setAttribute("data-relative-y", relativeY ? "on" : "off");

  const map = widgetSeriesCache.get(wid) || new Map();
  const tagIds = item.tagIds || [];

  if (!tagIds.length) {
    if (emptyEl) emptyEl.hidden = false;
    if (legendEl) legendEl.innerHTML = "";
    stage.__tagChartHtml = "";
    stage.innerHTML = "";
    return;
  }
  if (emptyEl) emptyEl.hidden = true;

  if (legendEl) {
    const infoById = tagInfoById();
    legendEl.innerHTML = tagIds
      .map((id, idx) => {
        const col = CHART_COLORS[idx % CHART_COLORS.length];
        const info = infoById.get(id);
        const text = formatTagLegendLabel(info, id);
        const pathTitle = formatTagPathTitle(info, id);
        return `<span title="${escapeHtml(pathTitle)}"><i class="tagSwatch" style="background:${col}"></i>${escapeHtml(text)}</span>`;
      })
      .join("");
  }

  let chartRange = chartRangeFromControls();
  if (
    !chartRange ||
    !Number.isFinite(chartRange.startUs) ||
    !Number.isFinite(chartRange.endUs) ||
    chartRange.endUs <= chartRange.startUs
  ) {
    chartRange = defaultChartRange();
  }
  const domainStartT = chartRange.startUs;
  const domainEndT = chartRange.endUs;

  const series = tagIds
    .map((id) => {
      const pts = map.get(id) || [];
      const visiblePts = extendPointsToDomain(pts, domainStartT, domainEndT);
      const info = tagInfoById().get(id);
      const bounds = seriesYBounds(visiblePts);
      return {
        id,
        pts: visiblePts,
        label: tagLabels.get(id) || id,
        step: info?.prsStep === true,
        minY: bounds.minY,
        maxY: bounds.maxY
      };
    })
    .filter((s) => s.pts.length);

  if (!series.length) {
    stage.__tagChartHtml = "";
    ensureChartEmptyMessage(
      stage,
      "Нет данных за выбранный период. Нажмите «Применить диапазон времени»."
    );
    return;
  }

  const minT = domainStartT;
  const maxT = domainEndT;
  let minY = Infinity;
  let maxY = -Infinity;
  if (!relativeY) {
    for (const s of series) {
      minY = Math.min(minY, s.minY);
      maxY = Math.max(maxY, s.maxY);
    }
    if (!Number.isFinite(minY) || !Number.isFinite(maxY)) {
      minY = 0;
      maxY = 1;
    }
  } else {
    minY = 0;
    maxY = 1;
  }

  const W = Math.max(120, stage.clientWidth || 300);
  const H = Math.max(120, stage.clientHeight || 180);
  const padL = relativeY ? 28 : 44;
  const padR = 12;
  const padT = 10;
  const padB = 28;
  const plotH = Math.max(1, H - padT - padB);

  const sx = (t) => padL + ((t - minT) / (maxT - minT)) * (W - padL - padR);
  const makeSy = (lo, hi) => (y) => {
    const span = hi - lo || 1;
    return padT + (1 - (y - lo) / span) * plotH;
  };
  for (const s of series) {
    const lo = relativeY ? s.minY : minY;
    const hi = relativeY ? s.maxY : maxY;
    s.sy = makeSy(lo, hi);
  }
  const sy = (y) => series[0].sy(y);

  const parts = [
    `<svg class="tagChartSvg" viewBox="0 0 ${W} ${H}" width="100%" height="100%" preserveAspectRatio="none" role="img" aria-label="График">`,
    `<rect x="0" y="0" width="${W}" height="${H}" fill="transparent"/>`,
    `<line x1="${padL}" y1="${H - padB}" x2="${W - padR}" y2="${H - padB}" stroke="rgba(128,140,155,.45)" stroke-width="1"/>`,
    `<line x1="${padL}" y1="${padT}" x2="${padL}" y2="${H - padB}" stroke="rgba(128,140,155,.45)" stroke-width="1"/>`
  ];

  const tickCount = 5;
  if (!relativeY) {
    for (let i = 0; i < tickCount; i++) {
      const v = minY + ((maxY - minY) * i) / (tickCount - 1);
      const y = sy(v);
      parts.push(
        `<line x1="${padL - 4}" y1="${y.toFixed(1)}" x2="${padL}" y2="${y.toFixed(1)}" stroke="rgba(128,140,155,.55)" stroke-width="1"/>`,
        `<line x1="${padL}" y1="${y.toFixed(1)}" x2="${W - padR}" y2="${y.toFixed(1)}" stroke="rgba(128,140,155,.16)" stroke-width="1"/>`,
        `<text x="${padL - 7}" y="${(y + 3).toFixed(1)}" text-anchor="end" font-size="10" fill="rgba(128,140,155,.92)">${escapeHtml(formatAxisNumber(v))}</text>`
      );
    }
  } else {
    parts.push(
      `<text x="${padL - 4}" y="${(padT + 10).toFixed(1)}" text-anchor="end" font-size="9" fill="rgba(128,140,155,.78)">отн.</text>`
    );
  }

  const xTickCount = Math.max(2, Math.min(7, Math.floor((W - padL - padR) / 130) + 1));
  for (let i = 0; i < xTickCount; i++) {
    const t = minT + ((maxT - minT) * i) / (xTickCount - 1);
    const x = sx(t);
    const anchor = i === 0 ? "start" : i === xTickCount - 1 ? "end" : "middle";
    parts.push(
      `<line x1="${x.toFixed(1)}" y1="${padT}" x2="${x.toFixed(1)}" y2="${H - padB + 4}" stroke="rgba(128,140,155,.12)" stroke-width="1"/>`,
      `<text x="${x.toFixed(1)}" y="${H - 6}" text-anchor="${anchor}" font-size="10" fill="rgba(128,140,155,.9)">${escapeHtml(formatAxisTimeLabel(t))}</text>`
    );
  }

  series.forEach((s, idx) => {
    const col = CHART_COLORS[idx % CHART_COLORS.length];
    const sySeries = s.sy;
    const d = s.step ? stepPathFromPoints(s.pts, sx, sySeries) : linePathFromPoints(s.pts, sx, sySeries);
    parts.push(`<path d="${d}" fill="none" stroke="${col}" stroke-width="2.2" stroke-linejoin="round" stroke-linecap="round"/>`);
    for (const p of s.pts) {
      if (!isRealPoint(p)) continue;
      const [t, y] = p;
      parts.push(
        `<circle cx="${sx(t).toFixed(1)}" cy="${sySeries(y).toFixed(1)}" r="3.2" fill="${col}" stroke="rgba(255,255,255,.92)" stroke-width="1"/>`
      );
    }
  });
  parts.push("</svg>");
  const nextStageHtml = parts.join("");
  const panel = stage.closest(".tagChartPanel");
  if (stage.__tagChartHtml !== nextStageHtml) {
    stage.__tagChartHtml = nextStageHtml;
    replaceChartStageSvg(stage, nextStageHtml);
  }
  wireChartTooltip(panel, stage, series, { minT, maxT, minY, maxY, padL, padR, padT, padB, W, H });

};

const pointValueRaw = (raw) => {
  if (typeof raw === "number") return raw;
  if (raw && typeof raw === "object" && "value" in raw) return raw.value;
  if (typeof raw === "string") {
    const n = Number(raw);
    if (raw.trim() !== "" && Number.isFinite(n)) return n;
    return raw;
  }
  return raw;
};

const latestValueFromBlock = (block) => {
  const pts = Array.isArray(block?.data) ? block.data : [];
  let best = null;
  for (const p of pts) {
    if (!Array.isArray(p) || p.length < 2) continue;
    const timeFirst = looksLikePointTime(p[0]);
    const valueFirst = looksLikePointTime(p[1]);
    const t = pointTimeToUs(timeFirst || !valueFirst ? p[0] : p[1]);
    const y = pointValueRaw(timeFirst || !valueFirst ? p[1] : p[0]);
    if (!Number.isFinite(t)) continue;
    if (y === null || y === undefined || (typeof y === "number" && !Number.isFinite(y))) continue;
    if (!best || t >= best.timeUs) best = { timeUs: t, value: y };
  }
  return best;
};

const formatTagDisplayValue = (raw, tag) => {
  if (raw === null || raw === undefined) return "—";
  const units = normalize(tag?.prsMeasureUnits || "");
  const code = tag?.prsValueTypeCode;
  if (code === 2 || code === 4 || typeof raw === "string") {
    const text = normalize(raw);
    return units && !text.endsWith(units) ? `${text} ${units}` : text || "—";
  }
  const n = Number(raw);
  if (!Number.isFinite(n)) return normalize(raw) || "—";
  return units ? `${formatAxisNumber(n)} ${units}` : formatAxisNumber(n);
};

const drawValueWidget = (widgetEl, tagLabels) => {
  const wid = widgetEl.dataset.widgetId;
  const grid = widgetEl.querySelector("[data-value-grid]");
  if (!grid) return;

  const item = layoutState.find((x) => x.id === wid) || {};
  const tagIds = item.tagIds || [];
  const valueMap = widgetValuesCache.get(wid) || new Map();
  const infoById = tagInfoById();

  if (!tagIds.length) {
    grid.innerHTML = `<div class="tagValueEmpty muted">Выберите теги для отображения текущего значения.</div>`;
    return;
  }

  grid.innerHTML = tagIds
    .map((id, idx) => {
      const info = infoById.get(id);
      const latest = valueMap.get(id);
      const cn = escapeHtml(normalize(info?.cn || tagLabels.get(id) || id));
      const desc = normalize(info?.description || "");
      const val = latest ? formatTagDisplayValue(latest.value, info) : "—";
      const time = latest?.timeUs ? formatAxisTimeLabel(latest.timeUs) : "";
      const col = CHART_COLORS[idx % CHART_COLORS.length];
      const pathTitle = escapeHtml(formatTagPathTitle(info, id));
      return `<div class="tagValueCard" title="${pathTitle}">
        <div class="tagValueCard__head"><i class="tagSwatch" style="background:${col}"></i><span class="tagValueCard__name">${cn}</span></div>
        <div class="tagValueCard__value">${escapeHtml(val)}</div>
        ${desc ? `<div class="tagValueCard__desc muted">${escapeHtml(desc)}</div>` : ""}
        ${time ? `<div class="tagValueCard__time muted mono">${escapeHtml(time)}</div>` : ""}
      </div>`;
    })
    .join("");
};

const drawWidget = (widgetEl, tagLabels) => {
  const wid = widgetEl.dataset.widgetId;
  const item = layoutState.find((x) => x.id === wid) || {};
  if (isValueWidget(item)) drawValueWidget(widgetEl, tagLabels);
  else drawChart(widgetEl, tagLabels);
};

let allTags = [];
let tagIndexNodes = [];
let tagIndexNodesByDn = new Map();
let tagIndexTagNodes = [];
let tagsCatalogLoadPromise = null;
let tagsCatalogLoadedOnce = false;
const tagLabelById = () => new Map(allTags.map((t) => [t.id, t.cn]));
const tagInfoById = () => new Map(allTags.map((t) => [t.id, t]));

const extractTagsArray = (raw) => {
  if (!raw || typeof raw !== "object") return [];
  if (Array.isArray(raw.data)) return raw.data;
  if (Array.isArray(raw.Data)) return raw.Data;
  if (Array.isArray(raw.result?.data)) return raw.result.data;
  if (Array.isArray(raw.items)) return raw.items;
  if (Array.isArray(raw.tags)) return raw.tags;
  return [];
};

const attrFirst = (value) => {
  if (Array.isArray(value)) return value.length ? attrFirst(value[0]) : "";
  if (value && typeof value === "object") {
    return normalize(value.cn ?? value.name ?? value.id ?? value.value ?? JSON.stringify(value));
  }
  return normalize(value);
};

const tagDescription = (row) => attrFirst(row?.attributes?.description ?? row?.description ?? "");
const tagMeasureUnits = (row) =>
  attrFirst(row?.attributes?.prsMeasureUnits ?? row?.prsMeasureUnits ?? row?.measureUnits ?? row?.unit ?? "");
const tagPrsStep = (row) => {
  const v = row?.attributes?.prsStep ?? row?.prsStep ?? row?.step;
  const first = Array.isArray(v) ? v[0] : v;
  if (first && typeof first === "object") return tagPrsStep({ prsStep: first.value ?? first.cn ?? first.name });
  if (typeof first === "boolean") return first;
  if (typeof first === "number") return first !== 0;
  const s = normalize(first).toLowerCase();
  return s === "true" || s === "1" || s === "yes" || s === "да";
};

const tagPrsValueTypeCode = (row) => {
  const v = row?.attributes?.prsValueTypeCode ?? row?.prsValueTypeCode;
  const first = Array.isArray(v) ? v[0] : v;
  const n = Number(first);
  return Number.isFinite(n) ? n : null;
};

const tagMatchesValueTypeFilter = (tag, filter) => {
  if (!filter) return true;
  if (filter === "numeric") {
    const code = tag?.prsValueTypeCode;
    return code === 0 || code === 1;
  }
  return true;
};

const formatTagLegendLabel = (tag, fallbackId = "") => {
  if (!tag) return normalize(fallbackId);
  const cn = normalize(tag.cn || fallbackId);
  const description = normalize(tag.description);
  const units = normalize(tag.prsMeasureUnits);
  const parts = [cn];
  if (description && description !== cn) parts.push(description);
  if (units) parts.push(units);
  return parts.filter(Boolean).join(" · ");
};

const formatTagPathTitle = (tag, fallbackId = "") => normalize(tag?.path || tag?.entryDn || tag?.cn || fallbackId);

const buildTagsCatalogQuery = () => {
  const q = {
    base: "cn=objects,cn=prs",
    scope: 2,
    filter: { objectClass: ["prsObject", "prsTag"] },
    hierarchy: true,
    attributes: ["cn", "description", "objectClass", "entryDN", "prsMeasureUnits", "prsStep", "prsValueTypeCode"]
  };
  return `q=${encodeURIComponent(JSON.stringify(q))}`;
};

const tagsCatalogUrl = () => `${apiRoot()}/tags/?${buildTagsCatalogQuery()}`;

const nodeObjectClasses = (row) => {
  const v = row?.attributes?.objectClass ?? row?.objectClass ?? [];
  const arr = Array.isArray(v) ? v : [v];
  return new Set(arr.map((x) => normalize(x)).filter(Boolean));
};

const iterTagIndexNodes = (nodes, parentNames = []) => {
  const out = [];
  for (const n of nodes || []) {
    const nodeId = normalize(n?.id);
    if (!nodeId) continue;
    const attrs = n?.attributes || {};
    const classes = nodeObjectClasses(n);
    const cn = entityCn(n) || attrFirst(attrs.cn);
    const description = tagDescription(n);
    const entryDn = attrFirst(attrs.entryDN ?? attrs.entryDn ?? attrs.dn);
    const prsMeasureUnits = tagMeasureUnits(n);
    const prsStep = tagPrsStep(n);
    const prsValueTypeCode = tagPrsValueTypeCode(n);
    const base = parentNames.filter(Boolean).join(" / ");
    const path = base ? `${base} / ${cn}` : cn;
    const isObject = classes.has("prsObject");
    const isTag = classes.has("prsTag");
    out.push({ nodeId, cn, description, entryDn, path, prsMeasureUnits, prsStep, prsValueTypeCode, isObject, isTag });
    const nextParents = isObject && cn ? [...parentNames, cn] : parentNames;
    out.push(...iterTagIndexNodes(n.children || n.Children || [], nextParents));
  }
  return out;
};

const rebuildTagIndex = (roots) => {
  const nodes = iterTagIndexNodes(roots);
  const nodesByDn = new Map();
  for (const n of nodes) {
    const dn = normalize(n.entryDn).toLowerCase();
    if (dn) nodesByDn.set(dn, n);
  }
  tagIndexNodes = nodes;
  tagIndexNodesByDn = nodesByDn;
  tagIndexTagNodes = nodes.filter((n) => n.isTag && n.nodeId);
  return tagIndexTagNodes.map((n) => ({
    id: n.nodeId,
    cn: n.cn,
    path: n.path,
    entryDn: n.entryDn,
    description: n.description,
    prsMeasureUnits: n.prsMeasureUnits,
    prsStep: n.prsStep,
    prsValueTypeCode: n.prsValueTypeCode
  }));
};

const readAllTagsCatalog = async () => {
  const raw = await peresvetGetJson(tagsCatalogUrl(), { cache: "no-store" });
  return rebuildTagIndex(extractTagsArray(raw));
};

const fetchEnterpriseTags = async () => {
  let rows = [];
  let lastErr = null;
  try {
    rows = await readAllTagsCatalog();
  } catch (e) {
    lastErr = e;
    rows = [];
  }
  if (!rows.length && lastErr) {
    allTags = [];
    tagIndexNodes = [];
    tagIndexNodesByDn = new Map();
    tagIndexTagNodes = [];
    console.error("[tag-charts] Не удалось загрузить теги:", lastErr);
    tagsCatalogLoadedOnce = true;
    return allTags;
  }

  allTags = rows.sort((a, b) => a.cn.localeCompare(b.cn, "ru"));
  tagsCatalogLoadedOnce = true;

  return allTags;
};

const ensureTagsCatalogLoaded = () => {
  if (allTags.length) return Promise.resolve(allTags);
  if (!tagsCatalogLoadPromise) {
    tagsCatalogLoadPromise = fetchEnterpriseTags().finally(() => {
      tagsCatalogLoadPromise = null;
    });
  }
  return tagsCatalogLoadPromise;
};

const TAG_SEARCH_MAX = 56;
const TAG_SEARCH_DEBOUNCE_MS = 480;
const TAG_SEARCH_MIN_LEN = 2;

const escapeRegExp = (s) => String(s).replace(/[|\\{}()[\]^$+?.]/g, "\\$&");

/** Как в prs-inkscape-grafana/tag_index.py: кавычки и пробелы. */
const parseTagSearchQuery = (q) => {
  const out = [];
  const s = String(q || "");
  let i = 0;
  const n = s.length;
  while (i < n) {
    while (i < n && /\s/.test(s[i])) i++;
    if (i >= n) break;
    if (s[i] === '"') {
      i++;
      const buf = [];
      while (i < n) {
        const ch = s[i];
        if (ch === "\\" && i + 1 < n) {
          buf.push(s[i + 1]);
          i += 2;
          continue;
        }
        if (ch === '"') {
          i++;
          break;
        }
        buf.push(ch);
        i++;
      }
      const tok = buf.join("").trim();
      if (tok) out.push(tok);
      continue;
    }
    const start = i;
    while (i < n && !/\s/.test(s[i])) i++;
    const tok = s.slice(start, i).trim();
    if (tok) out.push(tok);
  }
  return out;
};

const cnMatchesToken = (cn, token) => {
  const cnL = normalize(cn).toLowerCase();
  const t = normalize(token);
  if (!t) return false;
  const tL = t.toLowerCase();
  if (tL === "*") return true;
  if (t.includes("*")) {
    const pat = `^${escapeRegExp(tL).replace(/\\\*/g, ".*")}$`;
    try {
      return new RegExp(pat, "i").test(cnL);
    } catch {
      return cnL.includes(tL.replace(/\*/g, ""));
    }
  }
  return cnL.includes(tL);
};

const dnParent = (dn) => {
  const s = normalize(dn);
  const idx = s.indexOf(",");
  if (idx < 0) return null;
  const p = s.slice(idx + 1).trim();
  return p || null;
};

const dnIsDescendant = (childDn, ancestorDn) => {
  const cd = normalize(childDn).toLowerCase();
  const ad = normalize(ancestorDn).toLowerCase();
  if (!cd || !ad) return false;
  return cd.endsWith(`,${ad}`);
};

const rankTagSearchMatch = (cn, token) => {
  const cnL = normalize(cn).toLowerCase();
  const t = normalize(token).toLowerCase().replace(/\*/g, "").trim();
  if (!t) return 2;
  if (cnL === t) return 0;
  if (cnL.startsWith(t)) return 1;
  return 2;
};

/** Иерархический поиск по cn и entryDN, как TagIndex.search в prs-inkscape-grafana. */
const tagSearchFilterForItem = (item) => (isChartWidget(item) ? "numeric" : null);

const searchTagsByQuery = (
  q,
  { maxResults = TAG_SEARCH_MAX, minLen = TAG_SEARCH_MIN_LEN, valueTypeFilter = null } = {}
) => {
  const toks = parseTagSearchQuery(q);
  if (!toks.length || !tagIndexNodes.length) return [];

  const nontrivial = toks.filter(
    (t) => t.trim() && t.trim() !== "*" && t.replace(/\*/g, "").trim().length >= minLen
  );
  if (!nontrivial.length && !toks.some((t) => t.trim() === "*")) return [];

  const matches = [];
  for (const t of toks) {
    const seg = tagIndexNodes.filter((n) => cnMatchesToken(n.cn, t));
    matches.push(seg);
    if (!seg.length) return [];
  }

  let prevDns = new Set(matches[0].map((n) => normalize(n.entryDn).toLowerCase()).filter(Boolean));
  if (!prevDns.size) return [];

  for (let si = 1; si < matches.length; si++) {
    const nextDns = new Set();
    for (const n of matches[si]) {
      const dn = normalize(n.entryDn).toLowerCase();
      if (!dn) continue;
      let p = dnParent(n.entryDn);
      while (p) {
        if (prevDns.has(p.toLowerCase())) {
          nextDns.add(dn);
          break;
        }
        p = dnParent(p);
      }
    }
    prevDns = nextDns;
    if (!prevDns.size) return [];
  }

  const lastTok = toks[toks.length - 1];
  const out = new Map();
  const tagById = tagInfoById();

  for (const dn of prevDns) {
    const node = tagIndexNodesByDn.get(dn);
    if (!node) continue;
    if (node.isTag) {
      const tag = tagById.get(node.nodeId);
      if (tag && tagMatchesValueTypeFilter(tag, valueTypeFilter)) out.set(tag.id, tag);
      continue;
    }
    if (node.isObject) {
      for (const tn of tagIndexTagNodes) {
        if (!tn.entryDn || !dnIsDescendant(tn.entryDn, node.entryDn)) continue;
        const tag = tagById.get(tn.nodeId);
        if (tag && tagMatchesValueTypeFilter(tag, valueTypeFilter)) out.set(tag.id, tag);
      }
    }
  }

  const items = [...out.values()];
  items.sort((a, b) => {
    const ra = rankTagSearchMatch(a.cn, lastTok);
    const rb = rankTagSearchMatch(b.cn, lastTok);
    if (ra !== rb) return ra - rb;
    const pa = (a.path || "").length;
    const pb = (b.path || "").length;
    if (pa !== pb) return pa - pb;
    return (a.path || "").localeCompare(b.path || "", "ru");
  });
  return items.slice(0, maxResults);
};

const scheduleWidgetDataFetch = (wrap) => {
  clearTimeout(wrap.__oeeTagApplyDebounce);
  wrap.__oeeTagApplyDebounce = setTimeout(() => {
    applyPeriodAndFetch().catch(() => {});
  }, 400);
};

const renderTagPickerChips = (chipsEl, item, wrap) => {
  chipsEl.innerHTML = "";
  const labs = tagLabelById();
  const ids = item.tagIds || [];
  if (!ids.length) {
    chipsEl.innerHTML = `<span class="tagPicker__chipsEmpty muted small">Ничего не выбрано</span>`;
    return;
  }
  for (const id of ids) {
    const chip = document.createElement("button");
    chip.type = "button";
    chip.className = "tagChip";
    chip.dataset.tagId = id;
    const lab = labs.get(id) || id;
    chip.innerHTML = `<span class="tagChip__text">${escapeHtml(lab)}</span><span class="tagChip__x" aria-hidden="true">×</span>`;
    chip.title = `Убрать: ${lab}`;
    chip.addEventListener("click", (ev) => {
      ev.preventDefault();
      item.tagIds = (item.tagIds || []).filter((x) => normalize(x) !== id);
      saveLayout(layoutState);
      const picker = chipsEl.closest(".tagPicker");
      const searchIn = picker?.querySelector(".tagPicker__search");
      const resultsEl = picker?.querySelector(".tagPicker__results");
      renderTagPickerChips(chipsEl, item, wrap);
      if (searchIn && resultsEl) renderTagPickerResults(resultsEl, item, searchIn.value, wrap);
      if (wrap) scheduleWidgetDataFetch(wrap);
      if (wrap) drawWidget(wrap, labs);
    });
    chipsEl.appendChild(chip);
  }
};

const renderTagPickerResults = (resultsEl, item, query, wrap) => {
  const q = normalize(query);
  if (!q) {
    resultsEl.hidden = true;
    resultsEl.innerHTML = "";
    return;
  }
  resultsEl.hidden = false;
  resultsEl.innerHTML = "";
  if (!allTags.length) {
    if (tagsCatalogLoadedOnce && !tagsCatalogLoadPromise) {
      resultsEl.innerHTML = `<div class="tagPicker__hint muted small">Нет данных для поиска</div>`;
      return;
    }
    resultsEl.innerHTML = `<div class="tagPicker__hint muted small">Загрузка тегов...</div>`;
    ensureTagsCatalogLoaded()
      .then(() => {
        if (allTags.length) renderTagPickerResults(resultsEl, item, query, wrap);
        else resultsEl.innerHTML = `<div class="tagPicker__hint muted small">Нет данных для поиска</div>`;
      })
      .catch((e) => {
        console.error("[tag-charts] Не удалось загрузить теги:", e);
        resultsEl.innerHTML = `<div class="tagPicker__hint muted small">Нет данных для поиска</div>`;
      });
    return;
  }
  const picked = new Set((item.tagIds || []).map(normalize));
  const list = searchTagsByQuery(q, { valueTypeFilter: tagSearchFilterForItem(item) });
  if (!list.length) {
    resultsEl.innerHTML = `<div class="tagPicker__hint muted small">Нет совпадений</div>`;
    return;
  }
  for (const t of list) {
    const isOn = picked.has(t.id);
    const row = document.createElement("div");
    row.className = "tagPicker__row" + (isOn ? " tagPicker__row--on" : "");
    row.dataset.tagId = t.id;
    row.setAttribute("role", "option");
    row.setAttribute("aria-selected", isOn ? "true" : "false");

    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "tagPicker__anchor";
    btn.title = isOn ? "Убрать из графика" : "Добавить в график";
    btn.setAttribute("aria-label", btn.title);
    btn.innerHTML = `<span class="tagPicker__anchorGlyph" aria-hidden="true">&#x2693;</span>`;

    const main = document.createElement("div");
    main.className = "tagPicker__main";
    const titleLine = escapeHtml(t.path || t.cn || t.id);
    const metaLine = `${escapeHtml(t.id)}${t.cn ? ` · ${escapeHtml(t.cn)}` : ""}`;
    main.innerHTML = `<div class="tagPicker__path">${titleLine}</div><div class="tagPicker__meta mono">${metaLine}</div>`;

    const onPick = (ev) => {
      ev.preventDefault();
      ev.stopPropagation();
      const set = new Set((item.tagIds || []).map(normalize));
      if (set.has(t.id)) set.delete(t.id);
      else set.add(t.id);
      item.tagIds = [...set];
      saveLayout(layoutState);
      const picker = resultsEl.closest(".tagPicker");
      const chipsEl = picker?.querySelector(".tagPicker__chips");
      if (chipsEl) renderTagPickerChips(chipsEl, item, wrap);
      renderTagPickerResults(resultsEl, item, picker?.querySelector(".tagPicker__search")?.value || "", wrap);
      if (wrap) scheduleWidgetDataFetch(wrap);
    };
    btn.addEventListener("click", onPick);
    row.addEventListener("click", (e) => {
      if (e.target.closest("button.tagPicker__anchor")) return;
      onPick(e);
    });

    row.append(btn, main);
    resultsEl.appendChild(row);
  }
};

