let pollTimer = null;

/** Таймер на htmlNode: onRender в Grafana выполняется многократно, локальная переменная не очищает старый interval. */
const stopPoll = () => {
  const stored = htmlNode.__oeeTagChartsPollTimer;
  if (stored != null) {
    clearInterval(stored);
    htmlNode.__oeeTagChartsPollTimer = null;
  }
  if (pollTimer != null) {
    clearInterval(pollTimer);
    pollTimer = null;
  }
};

const startRelativePoll = () => {
  stopPoll();
  const range = computeQueryRange();
  if (!range || range.kind !== "relative") return;
  const refMs = getUiRefreshMs();
  if (!(refMs > 0)) return;
  const timerId = setInterval(() => {
    const tickMs = getUiRefreshMs();
    if (!(tickMs > 0)) {
      stopPoll();
      return;
    }
    fetchAndDrawAll({ incremental: true, stripRefreshMs: tickMs }).catch(() => {});
  }, refMs);
  htmlNode.__oeeTagChartsPollTimer = timerId;
  pollTimer = timerId;
};

const getTimeFromText = () => normalize(el("timeFromText")?.value);
const getTimeToText = () => normalize(el("timeToText")?.value);

const updateRefreshControlState = () => {
