};

const getUiRefreshMs = () => {
  const v = Number(el("refreshInterval")?.value);
  return Number.isFinite(v) && v >= 0 ? v : 0;
};

const formatRecentLine = (from, to) => `${from} — ${to}`;

const readRecentRanges = () => {
  try {
    const arr = JSON.parse(localStorage.getItem(RECENT_RANGES_KEY()) || "[]");
    return Array.isArray(arr) ? arr.filter((x) => x && x.from && x.to).slice(0, 12) : [];
  } catch {
    return [];
  }
};

const pushRecentRange = (from, to) => {
  if (isRelativeTimeInput(from) || isRelativeTimeInput(to)) return;
  const row = { from, to };
  let cur = readRecentRanges().filter((x) => x.from !== from || x.to !== to);
  cur.unshift(row);
  cur = cur.slice(0, 12);
  try {
    localStorage.setItem(RECENT_RANGES_KEY(), JSON.stringify(cur));
  } catch {
    /* ignore */
  }
};

