const computeQueryRange = () => {
  const fromStr = getTimeFromText();
  const toStr = getTimeToText();
  if (!fromStr || !toStr) return null;
  const anchor = Date.now();
  let fromMs = parseTimeExpression(fromStr, anchor);
  let toMs = parseTimeExpression(toStr, anchor);
  const fromOffset = relativeNowOffsetMs(fromStr);
  const toOffset = relativeNowOffsetMs(toStr);
  if (normalize(toStr).toLowerCase() === "now" && fromOffset != null) {
    toMs = anchor;
    fromMs = anchor + fromOffset;
  } else if (normalize(fromStr).toLowerCase() === "now" && toOffset != null) {
    fromMs = anchor;
    toMs = anchor + toOffset;
  }
  if (!Number.isFinite(fromMs) || !Number.isFinite(toMs) || toMs <= fromMs) return null;
  const rel = isRelativeTimeInput(fromStr) || isRelativeTimeInput(toStr);
  if (!rel) {
    return { kind: "exact", startUs: msToUs(fromMs), endUs: msToUs(toMs) };
  }
  return { kind: "relative", startUs: msToUs(fromMs), endUs: msToUs(toMs), windowStartUs: msToUs(fromMs) };
};

const fetchAndDrawAll = async ({ incremental, stripRefreshMs } = {}) => {
  const range = computeQueryRange();
  if (!range) {
    window.alert("Укажите корректный интервал (начало раньше конца).");
    return;
  }
  const previousRange = getCurrentChartRange();
  setCurrentChartRange({ startUs: range.startUs, endUs: range.endUs });
  const fullSpanUs = range.endUs - range.startUs;
  const refreshSpanUs = Number.isFinite(stripRefreshMs) && stripRefreshMs > 0 ? msToUs(stripRefreshMs) : fullSpanUs;

  const lab = tagLabelById();

  for (const item of layoutState) {
    const ids = item.tagIds || [];
    const wrap = htmlNode.querySelector(`.dashWidget[data-widget-id="${item.id}"]`);
    if (!ids.length) {
      if (wrap) drawWidget(wrap, lab);
      continue;
    }

    try {
      if (isValueWidget(item)) {
        const raw = await peresvetReadDataAtGet(ids, range.endUs);
        const valueMap = new Map();
        for (const block of extractBlocksFromDataGet(raw)) {
          const tid = normalize(block?.tagId);
          const latest = latestValueFromBlock(block);
          if (tid && latest) valueMap.set(tid, latest);
        }
        widgetValuesCache.set(item.id, valueMap);
        if (wrap) {
          wrap.classList.remove("is-loading-data");
          drawValueWidget(wrap, lab);
        }
        continue;
      }

      let seriesMap;
      if (incremental && widgetSeriesCache.has(item.id)) {
        const fallbackStartUs = Math.max(range.startUs, range.endUs - refreshSpanUs);
        let requestStartUs =
          previousRange && Number.isFinite(previousRange.endUs)
            ? Math.max(range.startUs, previousRange.endUs)
            : fallbackStartUs;
        if (!Number.isFinite(requestStartUs) || requestStartUs >= range.endUs) requestStartUs = fallbackStartUs;

        const requestSpanUs = Math.max(1, range.endUs - requestStartUs);
        const maxCount = chartMaxCountForSpan(wrap, requestSpanUs, fullSpanUs);
        const rangeRaw = await peresvetReadDataGet(ids, requestStartUs, range.endUs, maxCount);
        seriesMap = widgetSeriesCache.get(item.id) || new Map();
        mergeDataGetIntoSeriesMap(seriesMap, rangeRaw);
        for (const [tid, pts] of seriesMap.entries()) {
          seriesMap.set(tid, trimWindowKeepingCarry(pts, range.startUs));
        }
      } else {
        const [beforeRaw, rangeRaw] = await Promise.all([
          peresvetReadDataAtGet(ids, range.startUs).catch((e) => {
            console.error("[tag-charts] Ошибка загрузки начальных значений:", e);
            return null;
          }),
          peresvetReadDataGet(ids, range.startUs, range.endUs, chartMaxCountForWidget(wrap))
        ]);
        seriesMap = seriesMapFromDataGet(beforeRaw, { real: false });
        mergeDataGetIntoSeriesMap(seriesMap, rangeRaw);
      }
      widgetSeriesCache.set(item.id, seriesMap);

      if (wrap) {
        wrap.classList.remove("is-loading-data");
        drawChart(wrap, lab);
      }
    } catch (e) {
      if (wrap) {
        wrap.classList.remove("is-loading-data");
        console.error("[tag-charts] Ошибка загрузки данных:", e);
      }
    }
  }
};

const applyPeriodAndFetch = async () => {
  const range = computeQueryRange();
  if (!range) {
    window.alert("Укажите корректный интервал.");
    return;
  }
  stopPoll();
  writePeriodPrefs({
    mode: range.kind,
    refreshMs: getUiRefreshMs(),
    timeFrom: getTimeFromText(),
    timeTo: getTimeToText()
  });

  for (const w of htmlNode.querySelectorAll(".dashWidget")) w.classList.add("is-loading-data");
  await fetchAndDrawAll({ incremental: false });
  for (const w of htmlNode.querySelectorAll(".dashWidget")) w.classList.remove("is-loading-data");

  if (range.kind === "exact") {
    pushRecentRange(getTimeFromText(), getTimeToText());
    renderRecentRanges();
  }

  if (range.kind === "relative") startRelativePoll();
};

const ptrOpts = { capture: true };
const EDGE_SCROLL_PX = 88;
const EDGE_SCROLL_STEP = 16;
const EDGE_SCROLL_MS = 40;

const stopWidgetEdgeScroll = () => {
  const iv = htmlNode.__abrauTagChartsEdgeIv;
  if (iv != null) {
    clearInterval(iv);
    htmlNode.__abrauTagChartsEdgeIv = null;
  }
  htmlNode.__abrauTagChartsEdgePtr = null;
};

const applyWidgetEdgeAutoscroll = (clientX, clientY) => {
  htmlNode.__abrauTagChartsEdgePtr = { x: clientX, y: clientY };
  const root = themeRootEl;
  if (!root) return;
  const maxTop = Math.max(0, root.scrollHeight - root.clientHeight);
  const maxLeft = Math.max(0, root.scrollWidth - root.clientWidth);
  if (clientY < EDGE_SCROLL_PX) root.scrollTop = Math.max(0, root.scrollTop - EDGE_SCROLL_STEP);
  else if (clientY > window.innerHeight - EDGE_SCROLL_PX) root.scrollTop = Math.min(maxTop, root.scrollTop + EDGE_SCROLL_STEP);
  if (clientX < EDGE_SCROLL_PX) root.scrollLeft = Math.max(0, root.scrollLeft - EDGE_SCROLL_STEP);
  else if (clientX > window.innerWidth - EDGE_SCROLL_PX) root.scrollLeft = Math.min(maxLeft, root.scrollLeft + EDGE_SCROLL_STEP);
};

const startWidgetEdgeScrollLoop = () => {
  if (htmlNode.__abrauTagChartsEdgeIv != null) return;
  htmlNode.__abrauTagChartsEdgeIv = setInterval(() => {
    const p = htmlNode.__abrauTagChartsEdgePtr;
    if (!p) return;
    applyWidgetEdgeAutoscroll(p.x, p.y);
  }, EDGE_SCROLL_MS);
};

const getCanvasMetrics = (canvas) => {
  const r = canvas.getBoundingClientRect();
  const cs = getComputedStyle(canvas);
  const padL = parseFloat(cs.paddingLeft) || 0;
  const padR = parseFloat(cs.paddingRight) || 0;
  const padT = parseFloat(cs.paddingTop) || 0;
  const padB = parseFloat(cs.paddingBottom) || 0;
  const gapX = parseFloat(cs.columnGap || cs.gap) || 10;
  const gapY = parseFloat(cs.rowGap || cs.gap) || 10;
  const innerW = Math.max(0, r.width - padL - padR - gapX * (GRID_COLS - 1));
  const colW = innerW / GRID_COLS;
  const rowTrack = parseFloat(cs.getPropertyValue("--gridRow")) || 88;
  const rowStep = rowTrack + gapY;
  return { r, padL, padR, padT, padB, gapX, gapY, colW, rowStep };
};

const setGridPlacement = (node, item) => {
  node.style.gridColumn = `${item.x + 1} / span ${item.w}`;
  node.style.gridRow = `${item.y + 1} / span ${item.h}`;
};

const syncCanvasScrollHeight = () => {
  const canvas = el("widgetCanvas");
  const col = canvas?.closest(".canvasCol");
  if (!canvas || !col) return;
  const maxRow = layoutState.reduce((m, it) => Math.max(m, it.y + it.h), 0);
  const cs = getComputedStyle(canvas);
  const rowTrack = parseFloat(cs.getPropertyValue("--gridRow")) || 88;
  const gapY = parseFloat(cs.rowGap || cs.gap) || 10;
  const padT = parseFloat(cs.paddingTop) || 0;
  const padB = parseFloat(cs.paddingBottom) || 0;
  const contentH = maxRow > 0 ? maxRow * rowTrack + Math.max(0, maxRow - 1) * gapY : 0;
  const minH = Math.max(col.clientHeight, padT + padB + contentH);
  canvas.style.minHeight = `${Math.ceil(minH)}px`;
};

const scrollWidgetIntoView = (widgetId) => {
  const wrap = htmlNode.querySelector(`.dashWidget[data-widget-id="${widgetId}"]`);
  const col = el("widgetCanvas")?.closest(".canvasCol");
  if (!wrap || !col) return;
  requestAnimationFrame(() => {
    const wrapRect = wrap.getBoundingClientRect();
    const colRect = col.getBoundingClientRect();
    if (wrapRect.bottom > colRect.bottom - 8) {
      col.scrollTop += wrapRect.bottom - colRect.bottom + 16;
    } else if (wrapRect.top < colRect.top + 8) {
      col.scrollTop += wrapRect.top - colRect.top - 16;
    }
  });
};

