      saveLayout(layoutState);
      redrawAllWidgets();
      applyPeriodAndFetch().catch(() => {});
    });

    let dragActive = false;
    let resizeActive = false;
    let dragRaf = 0;
    let resizeRaf = 0;
    let dragPending = null;
    let resizePending = null;
    let orig;
    let dragGrabClient = null;
    let resizeGrabClient = null;

    const applyDragFromPointer = (clientX, clientY) => {
      if (!dragActive || !dragGrabClient) return;
      const m = getCanvasMetrics(canvas);
      const cellW = m.colW + m.gapX;
      const cellH = m.rowStep;
      const targetLeft = clientX - dragGrabClient.offX;
      const targetTop = clientY - dragGrabClient.offY;
      let newX = Math.floor((targetLeft - m.r.left - m.padL) / cellW);
      let newY = Math.floor((targetTop - m.r.top - m.padT) / cellH);
      if (!Number.isFinite(newX) || newX < 0) newX = 0;
      if (!Number.isFinite(newY) || newY < 0) newY = 0;
      newX = Math.min(GRID_COLS - orig.w, newX);
      const nx = clampItem({ ...item, x: newX, y: newY, w: orig.w, h: orig.h });
      if (nx.x === item.x && nx.y === item.y) return;
      Object.assign(item, nx);
      setGridPlacement(wrap, item);
    };

    const applyResizeFromPointer = (clientX, clientY) => {
      if (!resizeActive || !resizeGrabClient) return;
      const m = getCanvasMetrics(canvas);
      const strideX = Math.max(1, m.colW + m.gapX);
      const strideY = Math.max(1, m.rowStep);
      const dcx = clientX - resizeGrabClient.x;
      const dcy = clientY - resizeGrabClient.y;
      const deltaCols = Math.trunc(dcx / strideX);
      const deltaRows = Math.trunc(dcy / strideY);
      const nw = Math.min(GRID_COLS - orig.x, Math.max(GRID_MIN_W, orig.w + deltaCols));
      const nh = Math.max(2, orig.h + deltaRows);
      const test = clampItem({ ...item, x: orig.x, y: orig.y, w: nw, h: nh });
      if (test.w === item.w && test.h === item.h) return;
      Object.assign(item, test);
      packGridLayout(layoutState);
      syncCanvasDomToLayout();
    };

    const onDragMove = (ev) => {
      if (!dragActive) return;
      ev.preventDefault();
      applyWidgetEdgeAutoscroll(ev.clientX, ev.clientY);
      dragPending = { clientX: ev.clientX, clientY: ev.clientY };
      if (dragRaf) return;
      dragRaf = window.requestAnimationFrame(() => {
        dragRaf = 0;
        const p = dragPending;
        dragPending = null;
        if (!dragActive || !p) return;
        applyDragFromPointer(p.clientX, p.clientY);
      });
    };

    const onDragUp = () => {
      if (dragRaf) {
        window.cancelAnimationFrame(dragRaf);
        dragRaf = 0;
      }
      if (dragPending) {
        applyDragFromPointer(dragPending.clientX, dragPending.clientY);
        dragPending = null;
      }
      dragActive = false;
      dragGrabClient = null;
      stopWidgetEdgeScroll();
      wrap.classList.remove("is-dragging");
      document.removeEventListener("pointermove", onDragMove, ptrOpts);
      document.removeEventListener("pointerup", onDragUp, ptrOpts);
      document.removeEventListener("pointercancel", onDragUp, ptrOpts);
      packGridLayout(layoutState);
      saveLayout(layoutState);
      syncCanvasDomToLayout();
    };

    drag.addEventListener("pointerdown", (ev) => {
      if (ev.button !== 0) return;
      ev.preventDefault();
      ev.stopPropagation();
      dragActive = true;
      orig = { ...item };
      const wr = wrap.getBoundingClientRect();
      dragGrabClient = { offX: ev.clientX - wr.left, offY: ev.clientY - wr.top };
      startWidgetEdgeScrollLoop();
      wrap.classList.add("is-dragging");
      try {
        drag.setPointerCapture(ev.pointerId);
      } catch {
        /* ignore */
      }
      document.addEventListener("pointermove", onDragMove, ptrOpts);
      document.addEventListener("pointerup", onDragUp, ptrOpts);
      document.addEventListener("pointercancel", onDragUp, ptrOpts);
    });

    const onResizeMove = (ev) => {
      if (!resizeActive) return;
      ev.preventDefault();
      applyWidgetEdgeAutoscroll(ev.clientX, ev.clientY);
      resizePending = { clientX: ev.clientX, clientY: ev.clientY };
      if (resizeRaf) return;
      resizeRaf = window.requestAnimationFrame(() => {
        resizeRaf = 0;
        const p = resizePending;
        resizePending = null;
        if (!resizeActive || !p) return;
        applyResizeFromPointer(p.clientX, p.clientY);
      });
    };

    const onResizeUp = () => {
      if (resizeRaf) {
        window.cancelAnimationFrame(resizeRaf);
        resizeRaf = 0;
      }
      if (resizePending) {
        applyResizeFromPointer(resizePending.clientX, resizePending.clientY);
        resizePending = null;
      }
      resizeActive = false;
      resizeGrabClient = null;
      stopWidgetEdgeScroll();
      wrap.classList.remove("is-resizing");
      document.removeEventListener("pointermove", onResizeMove, ptrOpts);
      document.removeEventListener("pointerup", onResizeUp, ptrOpts);
      document.removeEventListener("pointercancel", onResizeUp, ptrOpts);
      saveLayout(layoutState);
    };

    resize.addEventListener("pointerdown", (ev) => {
      if (ev.button !== 0) return;
      ev.preventDefault();
      ev.stopPropagation();
      resizeActive = true;
      orig = { ...item };
      resizeGrabClient = { x: ev.clientX, y: ev.clientY };
      startWidgetEdgeScrollLoop();
      wrap.classList.add("is-resizing");
      try {
        resize.setPointerCapture(ev.pointerId);
      } catch {
        /* ignore */
      }
      document.addEventListener("pointermove", onResizeMove, ptrOpts);
      document.addEventListener("pointerup", onResizeUp, ptrOpts);
      document.addEventListener("pointercancel", onResizeUp, ptrOpts);
    });

    drawWidget(wrap, labs);

    if (stage) {
      const ro = new ResizeObserver(() => {
        const r = stage.getBoundingClientRect();
        const sizeKey = `${Math.round(r.width)}x${Math.round(r.height)}`;
        if (wrap.__tagChartSizeKey === sizeKey) return;
        wrap.__tagChartSizeKey = sizeKey;
        window.requestAnimationFrame(() => drawChart(wrap, tagLabelById()));
      });
      ro.observe(stage);
      wrap.__tagChartRo = ro;
    }
  });
  syncCanvasScrollHeight();
};

const destroyCanvasObservers = () => {
  for (const n of htmlNode.querySelectorAll(".dashWidget")) {
    if (n.__tagChartRo) {
      try {
        n.__tagChartRo.disconnect();
      } catch {
        /* ignore */
      }
      n.__tagChartRo = null;
    }
  }
};

const applySidebarCollapsed = (collapsed) => {
  const root = el("tagChartsRoot");
  if (!root) return;
  root.setAttribute("data-sidebar", collapsed ? "collapsed" : "expanded");
  try {
    localStorage.setItem(`abrau.tagCharts.sidebar.v1:${storeSeg()}`, collapsed ? "1" : "0");
  } catch {
    /* ignore */
  }
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      syncCanvasDomToLayout();
      const labs = tagLabelById();
      for (const w of htmlNode.querySelectorAll(".dashWidget")) drawWidget(w, labs);
      syncCanvasScrollHeight();
    });
  });
};

const toggleSidebarCollapsed = () => {
  const root = el("tagChartsRoot");
  if (!root) return;
  applySidebarCollapsed(root.getAttribute("data-sidebar") !== "collapsed");
};

const wireSidebar = () => {
  const root = el("tagChartsRoot");
  if (!root) return;
  let collapsed = false;
  try {
    collapsed = localStorage.getItem(`abrau.tagCharts.sidebar.v1:${storeSeg()}`) === "1";
  } catch {
    collapsed = false;
  }
  applySidebarCollapsed(collapsed);
};


const tagChartsStorageKeys = () => [
  THEME_KEY,
  LAYOUT_KEY,
  PERIOD_KEY,
  SIDEBAR_WIDTH_KEY(),
  RECENT_RANGES_KEY(),
  SHARED_SEEN_KEY,
  `abrau.tagCharts.sidebar.v1:${storeSeg()}`
];

const resetTagChartsLocalSettings = () => {
  for (const key of tagChartsStorageKeys()) {
    try {
      localStorage.removeItem(key);
    } catch {
      /* ignore */
    }
  }
};

const wireMetaMenu = () => {
  if (htmlNode.__oeeMetaMenuWired) return;
  htmlNode.__oeeMetaMenuWired = true;
  const trigger = el("metaMenuTrigger");
  const panel = el("metaMenuPanel");
  if (!trigger || !panel) return;

  const setOpen = (open) => {
    trigger.setAttribute("aria-expanded", open ? "true" : "false");
    if (open) panel.removeAttribute("hidden");
    else panel.setAttribute("hidden", "");
  };

  trigger.addEventListener("click", (ev) => {
    ev.stopPropagation();
    setOpen(panel.hasAttribute("hidden"));
  });

  htmlNode.addEventListener("click", (ev) => {
    if (panel.hasAttribute("hidden")) return;
    const path = typeof ev.composedPath === "function" ? ev.composedPath() : [];
    if (path.includes(trigger) || path.includes(panel)) return;
    setOpen(false);
  });

  for (const btn of panel.querySelectorAll("[data-theme-set]")) {
    btn.addEventListener("click", () => setOpen(false));
  }

  el("resetSettingsBtn")?.addEventListener("click", () => {
    setOpen(false);
    const ok = window.confirm(
      "Сбросить все локальные настройки доски и загрузить конфигурацию с сервера?"
    );
    if (!ok) return;
    resetTagChartsLocalSettings();
    window.location.reload();
  });
};

const readSidebarWidthPx = () => {
  try {
    const raw = localStorage.getItem(SIDEBAR_WIDTH_KEY());
    const n = Number(raw);
    if (Number.isFinite(n)) return clampSidebarWidth(n);
  } catch {
    /* ignore */
  }
  return clampSidebarWidth(SIDEBAR_WIDTH_DEFAULT);
};

const applySidebarWidth = (px) => {
  const root = el("tagChartsRoot");
  if (!root) return;
  const w = clampSidebarWidth(px);
  root.style.setProperty("--sidebarW", `${Math.round(w)}px`);
};

const wireLayoutSplitter = () => {
  if (htmlNode.__oeeLayoutSplitterWired) return;
  htmlNode.__oeeLayoutSplitterWired = true;
  const sp = el("layoutSplitter");
  const root = el("tagChartsRoot");
  if (!sp || !root) return;

  sp.addEventListener("dblclick", (ev) => {
    ev.preventDefault();
    ev.stopPropagation();
    toggleSidebarCollapsed();
  });

  const readW = () => {
    const cs = getComputedStyle(root);
    const v = parseFloat(String(cs.getPropertyValue("--sidebarW") || "").trim());
    return clampSidebarWidth(Number.isFinite(v) && v > 0 ? v : SIDEBAR_WIDTH_DEFAULT);
  };

  sp.addEventListener("pointerdown", (ev) => {
    if (root.getAttribute("data-sidebar") === "collapsed") return;
    if (ev.button !== 0) return;
    ev.preventDefault();
    const startX = ev.clientX;
    const startW = readW();
    sp.classList.add("is-dragging");
    try {
      sp.setPointerCapture(ev.pointerId);
    } catch {
      /* ignore */
    }

    const onMove = (e) => {
      const dx = e.clientX - startX;
      applySidebarWidth(startW + dx);
    };
    const onUp = (e) => {
      sp.classList.remove("is-dragging");
      try {
        sp.releasePointerCapture(e.pointerId);
      } catch {
        /* ignore */
      }
      sp.removeEventListener("pointermove", onMove);
      sp.removeEventListener("pointerup", onUp);
      sp.removeEventListener("pointercancel", onUp);
      try {
        const fin = readW();
        localStorage.setItem(SIDEBAR_WIDTH_KEY(), String(Math.round(fin)));
      } catch {
        /* ignore */
      }
    };
    sp.addEventListener("pointermove", onMove);
    sp.addEventListener("pointerup", onUp);
    sp.addEventListener("pointercancel", onUp);
  });

  if (!htmlNode.__oeeSidebarResizeWired) {
    htmlNode.__oeeSidebarResizeWired = true;
    let resizeT = null;
    window.addEventListener("resize", () => {
      clearTimeout(resizeT);
      resizeT = setTimeout(() => {
        if (root.getAttribute("data-sidebar") === "collapsed") return;
        const cs = getComputedStyle(root);
        const v = parseFloat(String(cs.getPropertyValue("--sidebarW") || "").trim());
        if (!Number.isFinite(v)) return;
        applySidebarWidth(v);
        try {
          localStorage.setItem(SIDEBAR_WIDTH_KEY(), String(Math.round(clampSidebarWidth(v))));
        } catch {
          /* ignore */
        }
      }, 120);
    });
  }
};

const applyRefreshIntervalNow = () => {
  const refMs = getUiRefreshMs();
  writePeriodPrefs({
    ...readPeriodPrefs(),
    refreshMs: refMs
  });
  startRelativePoll();
  const range = computeQueryRange();
  if (range?.kind === "relative" && refMs > 0) {
    fetchAndDrawAll({ incremental: true, stripRefreshMs: refMs }).catch(() => {});
  }
};

const populateRefreshIntervalOptions = () => {
  const refSel = el("refreshInterval");
  if (!refSel || refSel.options.length) return refSel;
  refSel.innerHTML = REFRESH_OPTIONS.map((o) => `<option value="${o.ms}">${o.label}</option>`).join("");
  return refSel;
};

const wireRefreshIntervalControl = () => {
  populateRefreshIntervalOptions();
  updateRefreshControlState();
};

const ensureRefreshIntervalListener = () => {
  if (htmlNode.__oeeRefreshIntervalDelegated) return;
  htmlNode.__oeeRefreshIntervalDelegated = true;
  htmlNode.addEventListener(
    "change",
    (e) => {
      const t = e.target;
      if (!t || t.id !== "refreshInterval") return;
      applyRefreshIntervalNow();
    },
    true
  );
};

const wirePeriodControls = () => {
  ensureRefreshIntervalListener();
  wireRefreshIntervalControl();

  if (htmlNode.__oeeTimePickWired) return;
  htmlNode.__oeeTimePickWired = true;

  const refSel = populateRefreshIntervalOptions();

  const prefs = readPeriodPrefs();
  if (prefs.timeFrom) el("timeFromText").value = prefs.timeFrom;
  if (prefs.timeTo) el("timeToText").value = prefs.timeTo;
  if (!el("timeFromText")?.value) el("timeFromText").value = "now-6h";
  if (!el("timeToText")?.value) el("timeToText").value = "now";
  if (Number.isFinite(prefs.refreshMs) && refSel) refSel.value = String(prefs.refreshMs);
  const initialRange = computeQueryRange();
  setCurrentChartRange(initialRange ? { startUs: initialRange.startUs, endUs: initialRange.endUs } : null);

  el("timeFromText")?.addEventListener("input", () => {
    setActiveQuickPreset(null);
    updateRefreshControlState();
  });
  el("timeToText")?.addEventListener("input", () => {
    setActiveQuickPreset(null);
    updateRefreshControlState();
  });

  el("periodApply")?.addEventListener("click", () => applyPeriodAndFetch().catch(() => {}));

  renderQuickRangeList();
  renderRecentRanges();
  updateRefreshControlState();

  const wireCal = (btnId, natId, textId) => {
    const btn = el(btnId);
    const nat = el(natId);
    const txt = el(textId);
    if (!btn || !nat || !txt) return;
    btn.addEventListener("click", () => {
      const cur = parseTimeExpression(txt.value, Date.now());
      if (Number.isFinite(cur)) nat.value = msToDatetimeLocalValue(cur);
      try {
        nat.showPicker?.();
      } catch {
        nat.focus();
      }
    });
    nat.addEventListener("change", () => {
      const v = nat.value;
      if (!v) return;
      const ms = Date.parse(v);
      if (Number.isFinite(ms)) txt.value = new Date(ms).toISOString();
    });
  };
  wireCal("timeFromCal", "timeFromNative", "timeFromText");
  wireCal("timeToCal", "timeToNative", "timeToText");
};

const wireAddWidget = () => {
  if (htmlNode.__oeeAddWidgetWired) return;
  htmlNode.__oeeAddWidgetWired = true;
  el("addChartWidget")?.addEventListener("click", () => {
    const { x, y } = findFreeSlot(layoutState, 12, 3);
    const item = clampItem({ id: newWidgetId(), type: WIDGET_TYPE_CHART, x, y, w: 12, h: 3, tagIds: [] });
    layoutState.push(item);
    saveLayout(layoutState);
    redrawAllWidgets();
    scrollWidgetIntoView(item.id);
  });
  el("addValueWidget")?.addEventListener("click", () => {
    const { x, y } = findFreeSlot(layoutState, 8, 2);
    const item = clampItem({ id: newWidgetId(), type: WIDGET_TYPE_VALUE, x, y, w: 8, h: 2, tagIds: [] });
    layoutState.push(item);
    saveLayout(layoutState);
    redrawAllWidgets();
    scrollWidgetIntoView(item.id);
  });
};

const redrawAllWidgets = () => {
  destroyCanvasObservers();
  renderCanvas();
  migrateLegacySelectTagPickers();
  const labs = tagLabelById();
  for (const w of htmlNode.querySelectorAll(".dashWidget")) drawWidget(w, labs);
  syncCanvasScrollHeight();
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      applySidebarWidth(readSidebarWidthPx());
      syncCanvasScrollHeight();
    });
  });
};

const bootstrap = async () => {
  stopPoll();

  wireSidebar();
  wireMetaMenu();
  applySidebarWidth(readSidebarWidthPx());
  wireLayoutSplitter();
  wirePeriodControls();
  wireWidgetMenusGlobal();
  await wireSaveForAll();

  wireAddWidget();

  redrawAllWidgets();

  try {
    await fetchEnterpriseTags();
  } catch (e) {
    allTags = [];
    console.error("[tag-charts] Ошибка загрузки тегов:", e);
  }

  redrawAllWidgets();

  if (!htmlNode.__tagChartsBootOnce) {
    htmlNode.__tagChartsBootOnce = true;
    await applyPeriodAndFetch().catch(() => {});
  } else {
    startRelativePoll();
    const labs = tagLabelById();
    for (const w of htmlNode.querySelectorAll(".dashWidget")) drawWidget(w, labs);
    const needFetch = layoutState.some((it) => {
      if (!(it.tagIds || []).length) return false;
      if (isValueWidget(it)) {
        const cached = widgetValuesCache.get(it.id);
        return !cached || !cached.size;
      }
      const cached = widgetSeriesCache.get(it.id);
      return !cached || !cached.size;
    });
    if (needFetch) fetchAndDrawAll({ incremental: false }).catch(() => {});
    else {
      for (const w of htmlNode.querySelectorAll(".dashWidget")) drawWidget(w, labs);
    }
  }
};

htmlNode.onpanelwillunmount = () => {
  stopPoll();
};

bootstrap().catch(() => {});
